extension SimilarGroup: Equatable, Hashable {
    public static func ==(lhs: SimilarGroup, rhs: SimilarGroup) -> Bool {
        if lhs.paths != rhs.paths {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(paths)
    }
}


