/**
 * Perceptually hash a batch of image paths the `image` crate can decode.
 */
public func dhashFiles(paths: [String]) -> PhashOutcome {
    return try!  FfiConverterTypePhashOutcome.lift(try! rustCall() {
    uniffi_nimbus_core_fn_func_dhash_files(
        FfiConverterSequenceString.lower(paths),$0
    )
})
}
/**
 * Perceptually hash a raw 8-bit luma buffer (Swift-decoded HEIC/RAW path).
 * Returns `None` if the buffer length doesn't match `width * height`.
 */
public func dhashLuma8(width: UInt32, height: UInt32, luma: Data) -> UInt64? {
    return try!  FfiConverterOptionUInt64.lift(try! rustCall() {
    uniffi_nimbus_core_fn_func_dhash_luma8(
        FfiConverterUInt32.lower(width),
        FfiConverterUInt32.lower(height),
        FfiConverterData.lower(luma),$0
    )
})
}
/**
 * Cluster perceptually-similar items. Swift accumulates all hashes (from
 * `dhash_files` and/or `dhash_luma8`) then calls this once.
 */
public func groupSimilar(items: [PhashItem], maxDistance: UInt32) -> [SimilarGroup] {
    return try!  FfiConverterSequenceTypeSimilarGroup.lift(try! rustCall() {
    uniffi_nimbus_core_fn_func_group_similar(
        FfiConverterSequenceTypePhashItem.lower(items),
        FfiConverterUInt32.lower(maxDistance),$0
    )
})
}
/**
 * Hash one size bucket of candidate paths and return byte-identical groups.
 * Swift calls this once per size bucket so it can drive progress + cancellation.
 */
public func hashFiles(paths: [String]) -> HashOutcome {
    return try!  FfiConverterTypeHashOutcome.lift(try! rustCall() {
    uniffi_nimbus_core_fn_func_hash_files(
        FfiConverterSequenceString.lower(paths),$0
    )
})
}

private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private var initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 26
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_nimbus_core_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_nimbus_core_checksum_func_dhash_files() != 19076) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_nimbus_core_checksum_func_dhash_luma8() != 30884) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_nimbus_core_checksum_func_group_similar() != 29003) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_nimbus_core_checksum_func_hash_files() != 17084) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

private func uniffiEnsureInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

